     8→/**
     9→ * Normalize and shorten a title string.
    10→ * - Replaces multiple whitespace with single space
    11→ * - Trims leading/trailing whitespace
    12→ * - Shortens to maxLength characters with ellipsis
    13→ */
    14→export function shortenTitle(
    15→  title: string | undefined | null,
    16→  maxLength = 50,
    17→): string {
    18→  if (!title) return "";
    19→
    20→  // Normalize: collapse whitespace and trim
    21→  const normalized = title.replace(/\s+/g, " ").trim();
    22→
    23→  if (normalized.length <= maxLength) {
    24→    return normalized;
    25→  }
    26→
    27→  // Shorten with ellipsis
    28→  return `${normalized.slice(0, maxLength - 1)}…`;
    29→}
