    48→function normalizePath(path: string): string {
    49→  const trimmed = path.trim().replace(/\\/g, "/");
    50→  if (trimmed === "") {
    51→    return "/";
    52→  }
    53→  const cleaned = trimmed.replace(TRAILING_SLASH_REGEX, "");
    54→  return cleaned === "" ? "/" : cleaned;
    55→}
    56→
    57→function compactPath(path: string, maxLength = 22): string {
    58→  const normalized = normalizePath(path);
    59→  if (normalized.length <= maxLength) {
    60→    return normalized;
    61→  }
    62→  const parts = normalized.split("/").filter(Boolean);
    63→  if (parts.length === 0) {
    64→    return normalized.slice(0, maxLength - 1) + "…";
    65→  }
    66→  const tail = parts.slice(-2).join("/");
    67→  if (tail.length + 2 <= maxLength) {
    68→    return `…/${tail}`;
    69→  }
    70→  return `…/${tail.slice(-maxLength + 2)}`;
    71→}
