    73→async function openViaBackend(app: OpenTarget["backendApp"], path: string) {
    74→  const response = await fetch("/api/open-in", {
    75→    method: "POST",
    76→    headers: { "Content-Type": "application/json", ...getAuthHeader() },
    77→    body: JSON.stringify({ app, path }),
    78→  });
    79→
    80→  if (response.ok) {
    81→    return;
    82→  }
    83→
    84→  let detail = "Failed to open application.";
    85→  try {
    86→    const data = await response.json();
    87→    if (data?.detail) {
    88→      detail = String(data.detail);
    89→    }
    90→  } catch (error) {
    91→    console.error("Failed to parse open-in error:", error);
    92→  }
    93→  throw new Error(detail);
    94→}
