     9→import { cn } from "@/lib/utils";
    10→import type { GitDiffStats } from "@/lib/api/models";
    11→import type { TokenUsage } from "@/hooks/wireTypes";
    12→import { useQueueStore } from "../../queue-store";
    13→import { useToolEventsStore } from "@/features/tool/store";
    14→import { ToolbarActivityIndicator, type ActivityDetail } from "../activity-status-indicator";
    15→import { ToolbarQueuePanel, ToolbarQueueTab } from "./toolbar-queue";
    16→import { ToolbarChangesPanel, ToolbarChangesTab } from "./toolbar-changes";
    17→import { ToolbarTodoPanel, ToolbarTodoTab } from "./toolbar-todo";
    18→import { ToolbarContextIndicator } from "./toolbar-context";
    19→
    20→// ─── Types ───────────────────────────────────────────────────
    21→
    22→type TabId = "queue" | "changes" | "todo";
    23→
    24→type PromptToolbarProps = {
    25→  gitDiffStats?: GitDiffStats | null;
    26→  isGitDiffLoading?: boolean;
    27→  workDir?: string | null;
    28→  activityStatus?: ActivityDetail;
    29→  usagePercent?: number;
    30→  usedTokens?: number;
    31→  maxTokens?: number;
    32→  tokenUsage?: TokenUsage | null;
    33→};
    34→
    35→// ─── Main toolbar ────────────────────────────────────────────
    36→
    37→export const PromptToolbar = memo(function PromptToolbarComponent({
    38→  gitDiffStats,
    39→  isGitDiffLoading,
    40→  workDir,
    41→  activityStatus,
    42→  usagePercent,
    43→  usedTokens,
    44→  maxTokens,
    45→  tokenUsage,
    46→}: PromptToolbarProps): ReactElement | null {
    47→  const queue = useQueueStore((s) => s.queue);
    48→  const todoItems = useToolEventsStore((s) => s.todoItems);
    49→  const [activeTab, setActiveTab] = useState<TabId | null>(null);
    50→  const prevQueueLenRef = useRef(0);
    51→
    52→  const stats = gitDiffStats;
    53→  const hasChanges = Boolean(stats?.isGitRepo && stats.hasChanges && stats.files && !stats.error);
    54→  const hasQueue = queue.length > 0;
    55→  const hasTodo = todoItems.length > 0;
    56→  const hasContext = usagePercent !== undefined && usedTokens !== undefined && maxTokens !== undefined;
    57→  const hasTabs = hasQueue || hasChanges || hasTodo;
    58→
    59→  // Auto-open queue tab when first item is added
    60→  useEffect(() => {
    61→    if (prevQueueLenRef.current === 0 && queue.length > 0) {
    62→      setActiveTab("queue");
    63→    }
    64→    prevQueueLenRef.current = queue.length;
    65→  }, [queue.length]);
    66→
    67→  // Auto-close tab when its data becomes empty
    68→  useEffect(() => {
    69→    if (activeTab === "queue" && !hasQueue) setActiveTab(null);
    70→    if (activeTab === "changes" && !hasChanges) setActiveTab(null);
    71→    if (activeTab === "todo" && !hasTodo) setActiveTab(null);
    72→  }, [activeTab, hasQueue, hasChanges, hasTodo]);
    73→
    74→  const toggleTab = useCallback((tab: TabId) => {
    75→    setActiveTab((prev) => (prev === tab ? null : tab));
    76→  }, []);
    77→
    78→  if (!(hasTabs || activityStatus || hasContext)) return null;
    79→
    80→  return (
    81→    <div className={cn("w-full px-1 sm:px-2 flex flex-col gap-1 mb-2", isGitDiffLoading && "opacity-70")}>
    82→      {/* ── Expanded panel ── */}
    83→      {activeTab && (
    84→        <div className={cn(
    85→          "rounded-md border border-border bg-background",
    86→          activeTab !== "changes" && "max-h-32 overflow-y-auto py-1 px-0.5",
    87→        )}>
    88→          {activeTab === "queue" && <ToolbarQueuePanel queue={queue} />}
    89→          {activeTab === "changes" && stats && (
    90→            <ToolbarChangesPanel stats={stats} workDir={workDir} />
    91→          )}
    92→          {activeTab === "todo" && (
    93→            <ToolbarTodoPanel items={todoItems} />
    94→          )}
    95→        </div>
    96→      )}
    97→
    98→      {/* ── Tab bar ── */}
    99→      <div className="flex items-center gap-1.5 px-1">
   100→        {activityStatus && (
   101→          <ToolbarActivityIndicator activity={activityStatus} />
   102→        )}
   103→
   104→        {hasQueue && (
   105→          <ToolbarQueueTab
   106→            count={queue.length}
   107→            isActive={activeTab === "queue"}
   108→            onToggle={() => toggleTab("queue")}
   109→          />
   110→        )}
   111→
   112→        {hasChanges && stats?.files && (
   113→          <ToolbarChangesTab
   114→            stats={stats}
   115→            isActive={activeTab === "changes"}
   116→            onToggle={() => toggleTab("changes")}
   117→          />
   118→        )}
   119→
   120→        {hasTodo && (
   121→          <ToolbarTodoTab
   122→            items={todoItems}
   123→            isActive={activeTab === "todo"}
   124→            onToggle={() => toggleTab("todo")}
   125→          />
   126→        )}
   127→
   128→        {hasContext && (
   129→          <ToolbarContextIndicator
   130→            usagePercent={usagePercent!}
   131→            usedTokens={usedTokens!}
   132→            maxTokens={maxTokens!}
   133→            tokenUsage={tokenUsage ?? null}
   134→            className="ml-auto"
   135→          />
   136→        )}
   137→      </div>
   138→    </div>
   139→  );
   140→});
