    94→  if (STOP_CHARS.test(query)) {
    95→    return null;
    96→  }
    97→
    98→  return {
    99→    start: triggerIndex,
   100→    end: safeCaret,
   101→    query,
   102→  };
   103→};
   104→
   105→const isSameRange = (a: MentionRange | null, b: MentionRange | null): boolean =>
   106→  a?.start === b?.start && a?.end === b?.end && a?.query === b?.query;
   107→
   108→const normalizePath = (value: string) => {
   109→  if (value === "." || value === "./" || value === "") {
   110→    return ".";
   111→  }
   112→  return value.replace(LEADING_DOT_SLASH, "");
   113→};
   114→
   115→const crawlWorkspace = async ({
   116→  sessionId,
   117→  listDirectory,
   118→}: {
   119→  sessionId: string;
   120→  listDirectory: UseFileMentionsArgs["listDirectory"];
   121→}): Promise<WorkspaceFile[]> => {
   122→  if (!listDirectory) {
   123→    return [];
   124→  }
   125→
   126→  const files: WorkspaceFile[] = [];
   127→  const queue: string[] = ["."];
   128→  const visited = new Set<string>();
   129→
   130→  while (
   131→    queue.length > 0 &&
   132→    files.length < MAX_WORKSPACE_FILES &&
   133→    visited.size < MAX_DIRECTORY_SCANS
   134→  ) {
   135→    const current = queue.shift() as string;
   136→    if (visited.has(current)) {
   137→      continue;
   138→    }
   139→    visited.add(current);
   140→
   141→    // "." should be treated as undefined for API root
   142→    const path = current === "." ? undefined : current;
   143→    const entries = await listDirectory(sessionId, path);
   144→
   145→    for (const entry of entries) {
   146→      const fullPath =
   147→        current === "."
   148→          ? entry.name
   149→          : `${normalizePath(current)}/${entry.name}`;
   150→      if (entry.type === "directory") {
   151→        queue.push(fullPath);
   152→        continue;
   153→      }
   154→      files.push({
   155→        path: fullPath,
   156→        size: entry.size,
   157→      });
   158→      if (files.length >= MAX_WORKSPACE_FILES) {
   159→        break;
   160→      }
   161→    }
   162→  }
   163→
   164→  return files;
   165→};
   166→
   167→const toAttachmentOptions = (
   168→  attachments: (FileUIPart & { id: string })[],
   169→): MentionOptionBase[] =>
   170→  attachments.map((attachment, index) => {
   171→    const label =
   172→      attachment.filename && attachment.filename.trim().length > 0
   173→        ? attachment.filename
   174→        : `Attachment ${index + 1}`;
   175→    return {
   176→      id: `upload-${attachment.id}`,
   177→      type: "attachment" as const,
   178→      label,
   179→      description: attachment.mediaType ?? "Pending upload",
   180→      insertValue: label,
   181→      meta: {
   182→        mediaType: attachment.mediaType,
   183→      },
   184→    };
   185→  });
   186→
   187→const toWorkspaceOptions = (files: WorkspaceFile[]): MentionOptionBase[] =>
   188→  files.map((file) => {
   189→    const segments = file.path.split("/");
   190→    const label = segments.at(-1) ?? file.path;
   191→    return {
   192→      id: `workspace-${file.path}`,
   193→      type: "workspace" as const,
   194→      label,
   195→      description: file.path,
   196→      insertValue: file.path,
   197→      meta: {
   198→        path: file.path,
   199→        size: file.size,
   200→      },
   201→    };
   202→  });
   203→
   204→const filterOptions = (
   205→  options: MentionOptionBase[],
   206→  query: string,
   207→  offset: number,
   208→): MentionOption[] => {
   209→  if (!options.length) {
   210→    return [];
   211→  }
   212→  const normalizedQuery = query.trim().toLowerCase();
   213→  const matchesQuery = (value?: string) =>
   214→    normalizedQuery.length === 0
   215→      ? true
   216→      : value?.toLowerCase().includes(normalizedQuery);
   217→
   218→  return options
   219→    .filter(
   220→      (option) =>
   221→        matchesQuery(option.insertValue) ||
   222→        matchesQuery(option.label) ||
   223→        matchesQuery(option.description),
   224→    )
   225→    .map((option, index) => ({
   226→      ...option,
   227→      order: offset + index,
   228→    }));
   229→};
   230→
   231→export const useFileMentions = ({
   232→  text,
   233→  setText,
   234→  textareaRef,
   235→  attachments,
   236→  sessionId,
   237→  listDirectory,
   238→}: UseFileMentionsArgs): UseFileMentionsReturn => {
   239→  const [range, setRange] = useState<MentionRange | null>(null);
   240→  const [activeIndex, setActiveIndex] = useState(0);
   241→  const [workspaceFiles, setWorkspaceFiles] = useState<WorkspaceFile[]>([]);
   242→  const [workspaceStatus, setWorkspaceStatus] = useState<
   243→    "idle" | "loading" | "ready" | "error"
   244→  >("idle");
   245→  const [workspaceError, setWorkspaceError] = useState<string | null>(null);
   246→  const workspaceRequestRef = useRef(0);
   247→
   248→  const attachmentOptions = useMemo(
   249→    () => toAttachmentOptions(attachments),
   250→    [attachments],
   251→  );
   252→  const workspaceOptions = useMemo(
   253→    () => toWorkspaceOptions(workspaceFiles),
   254→    [workspaceFiles],
   255→  );
   256→
   257→  const sections = useMemo(() => {
   258→    const attachmentsSection = filterOptions(
   259→      attachmentOptions,
   260→      range?.query ?? "",
   261→      0,
   262→    );
   263→    const workspaceSection = filterOptions(
   264→      workspaceOptions,
   265→      range?.query ?? "",
   266→      attachmentsSection.length,
   267→    );
   268→    return {
   269→      attachments: attachmentsSection,
   270→      workspace: workspaceSection,
   271→    };
   272→  }, [attachmentOptions, workspaceOptions, range?.query]);
   273→
   274→  const flatOptions = useMemo(
   275→    () => [...sections.attachments, ...sections.workspace],
   276→    [sections.attachments, sections.workspace],
   277→  );
   278→
   279→  useEffect(() => {
   280→    if (activeIndex < flatOptions.length) {
   281→      return;
   282→    }
   283→    setActiveIndex(flatOptions.length === 0 ? 0 : flatOptions.length - 1);
   284→  }, [activeIndex, flatOptions.length]);
   285→
   286→  useEffect(() => {
   287→    setActiveIndex(0);
   288→  }, []);
   289→
   290→  useEffect(() => {
   291→    setWorkspaceFiles([]);
   292→    setWorkspaceStatus("idle");
   293→    setWorkspaceError(null);
   294→    workspaceRequestRef.current += 1;
   295→  }, []);
   296→
   297→  const loadWorkspaceFiles = useCallback(async () => {
   298→    if (!(sessionId && listDirectory)) {
   299→      return;
   300→    }
   301→    setWorkspaceStatus("loading");
   302→    setWorkspaceError(null);
   303→    workspaceRequestRef.current += 1;
   304→    const requestId = workspaceRequestRef.current;
   305→    try {
   306→      const files = await crawlWorkspace({ sessionId, listDirectory });
   307→      if (workspaceRequestRef.current !== requestId) {
   308→        return;
   309→      }
   310→      setWorkspaceFiles(files);
   311→      setWorkspaceStatus("ready");
   312→    } catch (error) {
   313→      if (workspaceRequestRef.current !== requestId) {
   314→        return;
   315→      }
   316→      setWorkspaceStatus("error");
   317→      setWorkspaceError(
   318→        error instanceof Error
   319→          ? error.message
   320→          : "Failed to load workspace files",
   321→      );
   322→    }
   323→  }, [sessionId, listDirectory]);
   324→
   325→  useEffect(() => {
   326→    if (!range) {
   327→      return;
   328→    }
   329→    if (!(sessionId && listDirectory)) {
   330→      return;
   331→    }
   332→    if (workspaceStatus !== "idle" || workspaceFiles.length > 0) {
   333→      return;
   334→    }
   335→    loadWorkspaceFiles();
   336→  }, [
   337→    range,
   338→    sessionId,
   339→    listDirectory,
   340→    workspaceStatus,
   341→    workspaceFiles.length,
   342→    loadWorkspaceFiles,
   343→  ]);
   344→
   345→  useEffect(() => {
   346→    const caret = textareaRef.current?.selectionStart ?? text.length;
   347→    const next = detectMention(text, caret);
   348→    setRange((previous) => (isSameRange(previous, next) ? previous : next));
   349→  }, [text, textareaRef]);
   350→
   351→  const handleTextChange = useCallback(
   352→    (value: string, caret: number | null) => {
   353→      setRange(detectMention(value, caret));
   354→    },
   355→    [],
   356→  );
   357→
   358→  const handleCaretChange = useCallback(
   359→    (caret: number | null) => {
   360→      setRange(detectMention(text, caret));
   361→    },
   362→    [text],
   363→  );
   364→
   365→  const closeMenu = useCallback(() => {
   366→    setRange(null);
   367→  }, []);
   368→
   369→  const selectOption = useCallback(
   370→    (option?: MentionOption) => {
   371→      if (!range) {
   372→        return;
   373→      }
   374→      const target = option ?? flatOptions[activeIndex];
   375→      if (!target) {
   376→        return;
   377→      }
   378→
   379→      const mentionText = `@${target.insertValue}`;
   380→      const before = text.slice(0, range.start);
   381→      const after = text.slice(range.end);
   382→      const needsSpace =
   383→        after.length === 0 || NON_WHITESPACE_START.test(after) ? " " : "";
   384→      const nextValue = `${before}${mentionText}${needsSpace}${after}`;
   385→      const nextCaret = before.length + mentionText.length + needsSpace.length;
   386→
   387→      setText(nextValue);
   388→      setRange(null);
   389→      setActiveIndex(0);
   390→
   391→      requestAnimationFrame(() => {
   392→        const node = textareaRef.current;
   393→        if (!node) {
   394→          return;
   395→        }
   396→        node.focus();
   397→        node.setSelectionRange(nextCaret, nextCaret);
   398→      });
   399→    },
   400→    [range, flatOptions, activeIndex, text, setText, textareaRef],
   401→  );
   402→
   403→  const handleKeyDown = useCallback(
   404→    (event: KeyboardEvent<HTMLTextAreaElement>) => {
   405→      if (!range) {
   406→        return;
   407→      }
   408→
   409→      if (event.key === "ArrowDown") {
   410→        if (flatOptions.length === 0) {
   411→          return;
   412→        }
   413→        event.preventDefault();
   414→        setActiveIndex((previous) => (previous + 1) % flatOptions.length);
   415→        return;
   416→      }
   417→
   418→      if (event.key === "ArrowUp") {
   419→        if (flatOptions.length === 0) {
   420→          return;
   421→        }
   422→        event.preventDefault();
   423→        setActiveIndex((previous) =>
   424→          previous - 1 < 0
   425→            ? flatOptions.length - 1
   426→            : (previous - 1) % flatOptions.length,
   427→        );
   428→        return;
   429→      }
   430→
   431→      if (event.key === "Enter" || event.key === "Tab") {
   432→        if (flatOptions.length === 0) {
   433→          return;
   434→        }
   435→        event.preventDefault();
   436→        selectOption();
   437→        return;
   438→      }
   439→
   440→      if (event.key === "Escape") {
   441→        event.preventDefault();
   442→        closeMenu();
   443→      }
   444→    },
   445→    [range, flatOptions, selectOption, closeMenu],
   446→  );
   447→
   448→  const retryWorkspace = useCallback(() => {
   449→    loadWorkspaceFiles();
   450→  }, [loadWorkspaceFiles]);
   451→
   452→  return {
   453→    isOpen: Boolean(range),
   454→    query: range?.query ?? "",
   455→    flatOptions,
   456→    sections,
   457→    activeIndex,
   458→    setActiveIndex,
   459→    handleTextChange,
   460→    handleCaretChange,
   461→    handleKeyDown,
   462→    selectOption,
   463→    closeMenu,
   464→    workspaceStatus,
   465→    workspaceError,
   466→    retryWorkspace,
   467→  };
   468→};
   469→

